import fs from 'node:fs'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..')
const failures = []

const read = relativePath => fs.readFileSync(path.join(root, relativePath), 'utf8')

const assertContains = (source, needle, label) => {
	if (!source.includes(needle)) {
		failures.push(`${label} is missing ${needle}`)
	}
}

const assertNotContains = (source, needle, label) => {
	if (source.includes(needle)) {
		failures.push(`${label} still contains ${needle}`)
	}
}

const assertBefore = (source, first, second, label) => {
	const firstIndex = source.indexOf(first)
	const secondIndex = source.indexOf(second)
	if (firstIndex === -1 || secondIndex === -1 || firstIndex > secondIndex) {
		failures.push(`${label} expected ${first} before ${second}`)
	}
}

const collectSourceFiles = dir => {
	const current = path.join(root, dir)
	const files = []
	for (const entry of fs.readdirSync(current, { withFileTypes: true })) {
		const fullPath = path.join(current, entry.name)
		const relativePath = path.relative(root, fullPath)
		if (entry.isDirectory()) {
			files.push(...collectSourceFiles(relativePath))
		} else if (/\.(js|vue|css)$/.test(entry.name)) {
			files.push(relativePath)
		}
	}
	return files
}

for (const file of collectSourceFiles('src')) {
	const source = read(file)
	assertNotContains(source, '::v-deep', file)
	assertNotContains(source, "from '@nextcloud/vue'", file)
	assertNotContains(source, 'v-tooltip', file)
	assertNotContains(source, "from 'floating-vue'", file)
	assertNotContains(source, 'OC.dialogs.confirm', file)
	assertNotContains(source, 'confirm(', file)
	if (file !== 'src/services/http.js') {
		assertNotContains(source, "from '@nextcloud/axios'", file)
	}
}

